    33→		try {
    34→			const htmlPath = path.join(
    35→				process.cwd(),
    36→				'src',
    37→				'assets',
    38→				'trending-products.html',
    39→			);
    40→			const htmlContent = fs.readFileSync(htmlPath, 'utf8');
    41→
    42→			res.header('Content-Type', 'text/html');
    43→			res.send(htmlContent);
    44→		} catch (error: unknown) {
    45→			res.status(HttpStatusCode.InternalServerError).send({
    46→				error: 'Failed to load dashboard',
    47→				message: error instanceof Error ? error.message : 'Unknown error',
    48→			});
    49→		}
    50→	}
